import com.amazonaws.auth.{AWSCredentialsProvider, DefaultAWSCredentialsProviderChain}
import com.amazonaws.services.s3.AmazonS3
import com.amazonaws.services.s3.AmazonS3ClientBuilder
import com.amazonaws.services.s3.model.{Bucket, ObjectListing}

class AwsService(credentialsProvider: AWSCredentialsProvider = DefaultAWSCredentialsProviderChain.getInstance()) {

  private val s3Client: AmazonS3 = AmazonS3ClientBuilder.standard()
    .withCredentials(credentialsProvider)
    .withRegion("us-east-1") // Change to your desired region
    .build()

  def listBuckets(): List[Bucket] = {
    val buckets = s3Client.listBuckets()
    buckets.asScala.toList
  }

  def listObjects(bucketName: String): List[String] = {
    val objectListing: ObjectListing = s3Client.listObjects(bucketName)
    objectListing.getObjectSummaries.asScala.map(_.getKey).toList
  }
}

// Usage example
object Main extends App {
  val awsService = new AwsService()
  val buckets = awsService.listBuckets()
  buckets.foreach(bucket => println(bucket.getName))

  if (buckets.nonEmpty) {
    val objects = awsService.listObjects(buckets.head.getName)
    objects.foreach(println)
  }
}